const $ = (selector, scope = document) => scope.querySelector(selector);
const $$ = (selector, scope = document) => Array.from(scope.querySelectorAll(selector));

if ("scrollRestoration" in history) {
  history.scrollRestoration = "manual";
}

function releaseRouteHashScrollGuard() {
  document.getElementById("route-hash-scroll-guard")?.remove();
}

function isHashTargetInView(target) {
  const top = target.getBoundingClientRect().top;
  const scrollMargin = Number.parseFloat(window.getComputedStyle(target).scrollMarginTop) || 0;
  return Math.abs(top - scrollMargin) < 36;
}

function restoreRouteHashScroll() {
  const raw = window.location.hash;
  if (!raw || raw.length < 2) return;
  let id;
  try {
    id = decodeURIComponent(raw.slice(1));
  } catch {
    return;
  }
  const target = document.getElementById(id);
  if (!target || isHashTargetInView(target)) return;

  const html = document.documentElement;
  const { body } = document;
  const previousHtmlBehavior = html.style.scrollBehavior;
  const previousBodyBehavior = body.style.scrollBehavior;
  html.style.scrollBehavior = "auto";
  body.style.scrollBehavior = "auto";
  target.scrollIntoView({ block: "start", behavior: "instant" });
  html.style.scrollBehavior = previousHtmlBehavior;
  body.style.scrollBehavior = previousBodyBehavior;
}

let routeHashBootstrapped = false;
let routeHashClickRestoreUntil = 0;

function finishRouteHashBootstrap() {
  if (routeHashBootstrapped) return;
  routeHashBootstrapped = true;
  releaseRouteHashScrollGuard();
  enableRouteHashSync();
}

function scheduleRouteHashScroll() {
  if (!window.location.hash) {
    finishRouteHashBootstrap();
    return;
  }
  restoreRouteHashScroll();
  requestAnimationFrame(() => {
    restoreRouteHashScroll();
    finishRouteHashBootstrap();
  });
}

const routeSectionIds = ["hero", "news", "products", "technology", "about"];
let routeHashSyncReady = false;
let routeHashSyncRaf = 0;
let pendingRouteSectionId = null;

function setRouteHash(sectionId) {
  const base = `${window.location.pathname}${window.location.search}`;
  const nextHash = sectionId && sectionId !== "hero" ? `#${sectionId}` : "";
  const currentUrl = `${base}${window.location.hash}`;
  const nextUrl = `${base}${nextHash}`;
  if (currentUrl === nextUrl) return;
  history.replaceState(null, "", nextUrl);
}

function queueRouteHashSync(sectionId) {
  if (!routeHashSyncReady || !sectionId) return;
  pendingRouteSectionId = sectionId;
  if (routeHashSyncRaf) return;
  routeHashSyncRaf = requestAnimationFrame(() => {
    routeHashSyncRaf = 0;
    if (pendingRouteSectionId) setRouteHash(pendingRouteSectionId);
    pendingRouteSectionId = null;
  });
}

function enableRouteHashSync() {
  routeHashSyncReady = true;
}

