function addCjkLatinSpacing(text) {
  const cjk = "\\u3400-\\u9fff\\uf900-\\ufaff";
  const latin = "A-Za-z0-9";
  return text
    .replace(new RegExp(`([${cjk}])([${latin}])`, "g"), "$1 $2")
    .replace(new RegExp(`([${latin}])([${cjk}])`, "g"), "$1 $2");
}

function applyCjkLatinSpacing(scope = document.body) {
  if (currentLanguage === "en" || !scope) return;
  const walker = document.createTreeWalker(scope, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      const parent = node.parentElement;
      if (!parent || ["SCRIPT", "STYLE", "TEXTAREA", "INPUT"].includes(parent.tagName)) {
        return NodeFilter.FILTER_REJECT;
      }
      return /[\u3400-\u9fff\uf900-\ufaff][A-Za-z0-9]|[A-Za-z0-9][\u3400-\u9fff\uf900-\ufaff]/.test(node.nodeValue || "")
        ? NodeFilter.FILTER_ACCEPT
        : NodeFilter.FILTER_SKIP;
    }
  });
  const nodes = [];
  while (walker.nextNode()) nodes.push(walker.currentNode);
  nodes.forEach((node) => {
    node.nodeValue = addCjkLatinSpacing(node.nodeValue);
  });
}

function isChineseRoute(pathname = window.location.pathname) {
  const path = pathname.replace(/\\/g, "/");
  return path === "/cn" || path.startsWith("/cn/") || /(?:^|\/)cn\.html$/i.test(path);
}

function isEnglishRoute(pathname = window.location.pathname) {
  const path = pathname.replace(/\\/g, "/");
  return path === "/en" || path.startsWith("/en/") || /(?:^|\/)en\.html$/i.test(path);
}

const initialRouteLanguage = (() => {
  const params = new URLSearchParams(window.location.search);
  if (isEnglishRoute() || params.get("lang") === "en") {
    return { code: "en", label: "English" };
  }
  if (params.get("lang") === "zh-TW") {
    return { code: "zh-TW", label: "繁體中文" };
  }
  return { code: "zh-CN", label: "简体中文" };
})();
let currentLanguage = initialRouteLanguage.code;
let currentLanguageLabel = initialRouteLanguage.label;

