function resolveSiteHref(href) {
  const value = String(href || "").trim();
  if (!value || value.startsWith("#") || value.startsWith("mailto:") || value.startsWith("tel:")) {
    return value;
  }
  if (value.startsWith("./") || value.startsWith("../") || value.startsWith("//")) {
    return value;
  }
  if (/^https?:\/\//i.test(value)) {
    return value;
  }
  if (!value.startsWith("/")) {
    return value;
  }

  const url = new URL(value, window.location.origin);
  const normalizedPath = url.pathname.endsWith("/") && url.pathname.length > 1
    ? url.pathname.slice(0, -1)
    : url.pathname;
  const route = staticRouteMap[normalizedPath];
  if (!route) {
    return `${url.pathname}${url.search}${url.hash}`;
  }

  const params = new URLSearchParams(url.search);
  if (route.lang) {
    params.set("lang", route.lang);
  }
  const search = params.toString();
  return `${route.file}${search ? `?${search}` : ""}${url.hash}`;
}

function assetPath(path) {
  const value = String(path || "").trim();
  if (!value) return value;
  if (value.startsWith("./assets/")) {
    return value.replace("./assets/", "static/image/");
  }
  if (value.startsWith("assets/")) {
    return value.replace("assets/", "static/image/");
  }
  return value.replace(/^\.\//, "");
}

function initBrandAudio() {
  if (document.querySelector("[data-brand-audio]")) return;
  const storageKey = "chuyun.brandAudio.enabled";
  const timeKey = "chuyun.brandAudio.currentTime";
  const wrapper = document.createElement("div");
  wrapper.className = "brand-audio";
  wrapper.dataset.brandAudio = "";
  wrapper.innerHTML = `
    <audio src="static/audio/set-sail-chuyun-brand.mp3" preload="none" loop data-brand-audio-player></audio>
    <button class="brand-audio-control" type="button" data-brand-audio-toggle aria-label="播放品牌音乐" aria-pressed="false">
      <span class="brand-audio-control__icon" aria-hidden="true"></span>
      <span class="brand-audio-control__label">品牌音乐</span>
    </button>`;
  document.body.appendChild(wrapper);

  const audio = wrapper.querySelector("[data-brand-audio-player]");
  const button = wrapper.querySelector("[data-brand-audio-toggle]");
  const label = wrapper.querySelector(".brand-audio-control__label");
  const setPreference = (value) => {
    try {
      localStorage.setItem(storageKey, value);
    } catch {
      // Storage can be unavailable in some privacy modes; playback should still work.
    }
  };
  const getPreference = () => {
    try {
      return localStorage.getItem(storageKey);
    } catch {
      return null;
    }
  };
  const saveCurrentTime = () => {
    try {
      if (Number.isFinite(audio.currentTime)) {
        localStorage.setItem(timeKey, String(audio.currentTime));
      }
    } catch {
      // Ignore storage failures; audio controls still work.
    }
  };
  const restoreCurrentTime = () => {
    try {
      const saved = Number.parseFloat(localStorage.getItem(timeKey) || "0");
      if (Number.isFinite(saved) && saved > 0) {
        audio.currentTime = saved;
      }
    } catch {
      // Some browsers only allow seeking after metadata is ready.
    }
  };

  const setPlayingState = (isPlaying) => {
    button.classList.toggle("is-playing", isPlaying);
    button.setAttribute("aria-pressed", String(isPlaying));
    button.setAttribute("aria-label", isPlaying ? "暂停品牌音乐" : "播放品牌音乐");
    if (label) label.textContent = isPlaying ? "正在播放" : "品牌音乐";
  };

  const playAudio = async () => {
    try {
      restoreCurrentTime();
      await audio.play();
      setPreference("on");
      setPlayingState(true);
    } catch {
      setPreference("off");
      setPlayingState(false);
    }
  };

  const pauseAudio = () => {
    saveCurrentTime();
    audio.pause();
    setPreference("off");
    setPlayingState(false);
  };

  button.addEventListener("click", () => {
    if (audio.paused) {
      playAudio();
    } else {
      pauseAudio();
    }
  });

  audio.addEventListener("pause", () => setPlayingState(false));
  audio.addEventListener("play", () => {
    restoreCurrentTime();
    setPlayingState(true);
  });
  audio.addEventListener("timeupdate", saveCurrentTime);
  audio.addEventListener("loadedmetadata", restoreCurrentTime, { once: true });
  window.addEventListener("pagehide", saveCurrentTime);
  window.addEventListener("beforeunload", saveCurrentTime);

  if (getPreference() === "on") {
    window.setTimeout(playAudio, 180);
  }
}

