function isExternalHref(href) {
  const value = resolveSiteHref(href);
  if (!value || value.startsWith("#")) return false;
  if (value.startsWith("mailto:")) return true;
  if (value.startsWith("/") || value.startsWith("./") || value.startsWith("../")) return false;
  if (value.startsWith("//")) return true;
  if (/^https?:\/\//i.test(value)) {
    try {
      return new URL(value).origin !== window.location.origin;
    } catch {
      return true;
    }
  }
  return false;
}

function applyLinkTarget(link, href) {
  if (!link || !href) return;
  if (isExternalHref(href)) {
    link.setAttribute("target", "_blank");
    link.setAttribute("rel", "noopener");
  } else {
    link.removeAttribute("target");
    link.removeAttribute("rel");
  }
}

function normalizeInternalLinks(scope = document) {
  $$("a[href]", scope).forEach((link) => {
    const href = link.getAttribute("href");
    const resolvedHref = resolveSiteHref(href);
    if (resolvedHref && resolvedHref !== href) {
      link.setAttribute("href", resolvedHref);
    }
    applyLinkTarget(link, resolvedHref || href);
  });
}

