  setText(".hero__content p", copy.hero.subtitle);
  setText(".hero-button", copy.hero.button);
  setAttr(".hero-button", "href", copy.hero.url);

  setText("#news-title", copy.news.heading);
  setAttr("[data-news-prev]", "aria-label", copy.news.prev);
  setAttr("[data-news-next]", "aria-label", copy.news.next);
  setText("[data-open-news]", copy.news.more);
