function refreshProductsForLanguage() {
  const accordion = $("[data-product-accordion]");
  if (!accordion) return;
  accordion.innerHTML = "";
  delete accordion.dataset.drawerReady;
  if (currentProductKey) {
    setProduct(currentProductKey, { silent: true, motion: "initial" });
  } else {
    renderProductAccordion(null, "initial");
  }
}

function applyLanguage(code, label) {
  currentLanguage = code === "en" ? "en" : code === "zh-TW" ? "zh-TW" : "zh-CN";
  currentLanguageLabel = label || (currentLanguage === "en" ? "English" : currentLanguage === "zh-TW" ? "繁體中文" : "简体中文");
  updateStaticCopy();
  refreshProductsForLanguage();
}

function normalizeProductTool(item) {
  const fallbackDesc = isTraditionalLanguage()
    ? toTraditionalText("该产品入口可继续连接到详情页、试用申请或独立产品官网。")
    : "该产品入口可继续连接到详情页、试用申请或独立产品官网。";

  if (typeof item === "string") {
    return {
      title: item,
      kicker: "Product Tool",
      desc: currentLanguage === "en" ? "This product entry can connect to a detail page, trial request, or dedicated product website." : fallbackDesc,
      tone: "nova",
      url: currentLanguage === "en" ? "partner.html?lang=en" : "partner.html"
    };
  }

  return {
    title: item.title,
    kicker: item.kicker || "Product Tool",
    desc: item.desc || (currentLanguage === "en" ? "This product entry can connect to a detail page, trial request, or dedicated product website." : fallbackDesc),
    tone: item.tone || "nova",
    url: item.url || (currentLanguage === "en" ? "partner.html?lang=en" : "partner.html")
  };
}

function productListMarkup(items) {
  return items
    .map((item, index) => {
      const tool = normalizeProductTool(item);
      const href = resolveSiteHref(tool.url);
      const activeClass = index === 0 ? " class=\"is-active\"" : "";
      const ariaCurrent = index === 0 ? " aria-current=\"true\"" : "";
      const externalAttrs = isExternalHref(href) ? ' target="_blank" rel="noopener"' : "";
      return `<li><a href="${escapeHtml(href)}"${externalAttrs}${activeClass}${ariaCurrent} data-product-tool-index="${index}" data-product-link="${escapeHtml(tool.title)}">${escapeHtml(tool.title)}</a></li>`;
    })
    .join("");
}

function productTitleMarkup(key, title) {
  const escapedTitle = escapeHtml(title);
  if (currentLanguage === "en") {
    if (key === "sensenova" || key === "infra" || key === "city") {
      return `<span class="product-title-nowrap">${escapedTitle}</span>`;
    }
    return escapedTitle;
  }

  const mobileBreakAfter = {
    sensenova: "品牌孵化",
    infra: "运营中台",
    city: "数据运营"
  }[key];

  if (!mobileBreakAfter) return escapedTitle;

  const escapedToken = escapeHtml(mobileBreakAfter);
  const tokenIndex = escapedTitle.indexOf(escapedToken);
  if (tokenIndex < 0) return escapedTitle;

  const breakPoint = tokenIndex + escapedToken.length;
  const beforeBreak = escapedTitle.slice(0, breakPoint);
  const afterBreak = escapedTitle.slice(breakPoint).replace(/^\s+/, "");
  return `<span class="product-title-keep">${beforeBreak}</span> <br class="product-title-mobile-break" />${afterBreak}`;
}

function getCurrentProduct() {
  return getLocalizedProduct(currentProductKey);
}

function expandedProductMarkup(key, motion = "initial") {
  const item = getLocalizedProduct(key);
  const dynamicClass = item.dynamicBackground ? " product-expanded--dynamic" : "";
  const imageMarkup = item.dynamicBackground
    ? ""
    : `<img class="product-stage__image product-stage__image--${key}" src="${item.image}" alt="" data-product-image />`;
  return `
    <article class="product-expanded product-expanded--${key}${dynamicClass} glass-panel" data-product-expanded data-product-motion="${motion}">
      <div class="product-expanded__copy">
        <span class="product-number" data-product-number>${item.number}</span>
        <div>
          <h3 data-product-title>${productTitleMarkup(key, item.title)}</h3>
          <p data-product-subtitle>${escapeHtml(item.subtitle)}</p>
          <ul data-product-list>
            ${productListMarkup(item.links)}
          </ul>
        </div>
      </div>
      <div class="product-stage product-stage--${key}" aria-hidden="true">
        ${imageMarkup}
      </div>
      <span class="product-stage-hotspot" aria-hidden="true"></span>
    </article>
  `;
}

function setProductToolActive(buttons, activeButton) {
  buttons.forEach((button) => {
    const isActive = button === activeButton;
    button.classList.toggle("is-active", isActive);
    if (isActive) {
      button.setAttribute("aria-current", "true");
    } else {
      button.removeAttribute("aria-current");
    }
  });
}

function restoreDefaultProductTool(list) {
  const buttons = $$("[data-product-link]", list);
  if (buttons.length) {
    setProductToolActive(buttons, buttons[0]);
  }
}

function bindProductLinks() {
  $$("[data-product-list]").forEach((list) => {
    const buttons = $$("[data-product-link]", list);
    list.addEventListener("mouseleave", () => restoreDefaultProductTool(list));

    buttons.forEach((button) => {
      button.addEventListener("mouseenter", () => setProductToolActive(buttons, button));
      button.addEventListener("focus", () => setProductToolActive(buttons, button));
      button.addEventListener("blur", () => {
        if (!list.matches(":hover")) {
          restoreDefaultProductTool(list);
        }
      });
      button.addEventListener("click", (event) => {
        event.stopPropagation();
      });
    });
  });
}

function solutionCardMarkup(key) {
  const item = getLocalizedProduct(key);
  const tools = (item.links || []).slice(0, 3).map(normalizeProductTool);
  const href = resolveSiteHref(tools[0]?.url || (currentLanguage === "en" ? "partner.html?lang=en" : "partner.html"));
  const externalAttrs = isExternalHref(href) ? ' target="_blank" rel="noopener"' : "";
  return `
    <article class="solution-card solution-card--${key}">
      <a class="solution-card__link" href="${escapeHtml(href)}"${externalAttrs} aria-label="${escapeHtml(item.title)}"></a>
      <div class="solution-card__top">
        <span>${escapeHtml(item.number)}</span>
        <strong>${escapeHtml(tools[0]?.kicker || item.title)}</strong>
      </div>
      <h3>${productTitleMarkup(key, item.title)}</h3>
      <p>${escapeHtml(item.subtitle)}</p>
      <div class="solution-card__tags">
        ${tools.map((tool) => `<em>${escapeHtml(tool.title)}</em>`).join("")}
      </div>
      <div class="solution-card__arrow" aria-hidden="true">→</div>
    </article>
  `;
}

