function getNewsSlides() {
  return getCopy().news.slides || [];
}

function stopNewsCarousel() {
  window.clearInterval(newsCarouselTimer);
  newsCarouselTimer = 0;
}

function renderNewsCarouselImages() {
  const carousel = $("[data-news-carousel]");
  if (!carousel) return [];

  const slides = getNewsSlides();
  carousel.innerHTML = "";

  slides.forEach((slide, index) => {
    const image = document.createElement("img");
    image.className = `news-feature__image${index === newsActiveIndex ? " is-active" : ""}`;
    image.src = assetPath(`./assets/${slide.image}`);
    image.alt = "";
    image.decoding = "async";
    image.dataset.newsSlide = "";
    image.dataset.newsUrl = slide.url;
    if (slide.mediaOnly) image.dataset.newsMediaOnly = "";
    carousel.appendChild(image);
  });

  const mediaWords = document.createElement("div");
  mediaWords.className = "news-feature__media-words";
  mediaWords.setAttribute("aria-hidden", "true");
  mediaWords.innerHTML = `
    <span class="news-feature__media-word news-feature__media-word--home"></span>
    <span class="news-feature__media-word news-feature__media-word--scene"></span>
    <span class="news-feature__media-word news-feature__media-word--combined"></span>
  `;
  carousel.appendChild(mediaWords);

  return $$("[data-news-slide]", carousel);
}

function applyNewsSlideContent(index) {
  const slide = getNewsSlides()[index];
  const feature = $("[data-news]");
  if (!slide || !feature) return;

  feature.dataset.newsUrl = slide.url;
  feature.classList.toggle("news-feature--media-only", Boolean(slide.mediaOnly));

  $$(".news-feature__chips span", feature).forEach((item, chipIndex) => {
    const label = slide.chips?.[chipIndex] || "";
    item.textContent = label;
    item.hidden = !label;
  });

  const words = slide.mediaWords || [];
  setText(".news-feature__media-word--home", words[0] || "", feature);
  setText(".news-feature__media-word--scene", words[1] || "", feature);
  setText(".news-feature__media-word--combined", words[2] || "", feature);

  setText(".news-feature__copy h3", slide.title || "", feature);
  setText(".news-feature__copy strong", slide.strong || "", feature);
  setHtml(".news-feature__copy p", slide.body || "", feature);
  setText(".news-feature__cta", slide.button || "", feature);
}

function setNewsFeatureSlide(slideElements, activeIndex) {
  slideElements.forEach((slide, index) => {
    slide.classList.toggle("is-active", index === activeIndex);
  });

  const activeSlide = slideElements[activeIndex];
  const feature = activeSlide?.closest("[data-news]");
  if (!feature || !activeSlide) return;

  if (activeSlide.dataset.newsUrl) {
    feature.dataset.newsUrl = activeSlide.dataset.newsUrl;
  }

  newsActiveIndex = activeIndex;
  applyNewsSlideContent(activeIndex);
}

function restartNewsCarouselTimer(goToSlide) {
  stopNewsCarousel();
  const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  if (reduceMotion) return;

  let isPageScrolling = false;
  let scrollIdleTimer = 0;

  function handlePageScroll() {
    isPageScrolling = true;
    window.clearTimeout(scrollIdleTimer);
    scrollIdleTimer = window.setTimeout(() => {
      isPageScrolling = false;
    }, 360);
  }

  if (!window.__newsCarouselScrollBound) {
    window.addEventListener("scroll", handlePageScroll, { passive: true });
    window.__newsCarouselScrollBound = true;
  }

  newsCarouselTimer = window.setInterval(() => {
    if (isPageScrolling) return;
    const carousel = $("[data-news-carousel]");
    const slides = $$("[data-news-slide]", carousel);
    if (slides.length < 2) return;
    goToSlide((newsActiveIndex + 1) % slides.length);
  }, 4800);
}

function startNewsFeatureCarousel() {
  stopNewsCarousel();

  const carousel = $("[data-news-carousel]");
  if (!carousel) return;

  const slideConfig = getNewsSlides();
  if (!slideConfig.length) return;

  newsActiveIndex = Math.min(newsActiveIndex, slideConfig.length - 1);
  if (newsActiveIndex < 0) newsActiveIndex = 0;

  const slides = renderNewsCarouselImages();
  const feature = carousel.closest("[data-news]");
  feature?.classList.toggle("news-feature--single-slide", slides.length < 2);
  setNewsFeatureSlide(slides, newsActiveIndex);

  if (slides.length < 2) return;

  function goToSlide(nextIndex, manual = false) {
    const currentSlides = $$("[data-news-slide]", carousel);
    if (!currentSlides.length) return;
    setNewsFeatureSlide(currentSlides, nextIndex);
    if (manual) restartNewsCarouselTimer(goToSlide);
  }

  if (!feature.dataset.carouselReady) {
    feature.dataset.carouselReady = "true";
    $$("[data-news-prev], [data-news-next]", feature).forEach((button) => {
      button.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        const currentSlides = $$("[data-news-slide]", carousel);
        if (currentSlides.length < 2) return;
        const direction = button.matches("[data-news-prev]") ? -1 : 1;
        const nextIndex = (newsActiveIndex + direction + currentSlides.length) % currentSlides.length;
        goToSlide(nextIndex, true);
      });
    });
  }

  restartNewsCarouselTimer(goToSlide);
}

function refreshNewsFeature() {
  if (!$("[data-news-carousel]")) return;
  startNewsFeatureCarousel();
}

function productRowMarkup(key, modifiers = "") {
  const item = getLocalizedProduct(key);
  const ariaPrefix = currentLanguage === "en" ? "Expand " : isTraditionalLanguage() ? "展開" : "展开";
  return `
    <div class="product-row${modifiers}" data-product-row="${key}" role="button" tabindex="0" aria-label="${ariaPrefix}${item.title}" aria-expanded="false">
      <span>${item.number}</span>
      <div class="product-row__heading">
        <strong>${productTitleMarkup(key, item.title)}</strong>
        <small class="product-row__subtitle">${escapeHtml(item.subtitle)}</small>
      </div>
      <em class="product-row__toggle" aria-hidden="true"></em>
    </div>
  `;
}

function productDrawerMarkup(key) {
  return `
    <div class="product-drawer" data-product-item="${key}">
      ${productRowMarkup(key)}
      <div class="product-drawer__panel" aria-hidden="true">
        <div class="product-drawer__panel-inner">
          ${expandedProductMarkup(key)}
        </div>
      </div>
    </div>
  `;
}

function renderProductAccordion(activeKey, motion = "initial") {
  const accordion = $("[data-product-accordion]");
  if (!accordion) return;
  accordion.classList.add("solution-grid");
  accordion.innerHTML = productOrder.map((key) => solutionCardMarkup(key)).join("");
  applyCjkLatinSpacing(accordion);
}

function bindProductRows() {
  $$("[data-product-row]").forEach((row) => {
    row.addEventListener("click", () => {
      setProduct(row.dataset.productRow, { silent: true });
    });
    row.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        setProduct(row.dataset.productRow, { silent: true });
      }
    });
  });
}

function setProduct(key, options = {}) {
  const catalog = productCatalog();
  const nextKey = catalog[key] ? key : "sensenova";
  const item = getLocalizedProduct(nextKey);
  const previousIndex = productOrder.indexOf(currentProductKey);
  const nextIndex = productOrder.indexOf(nextKey);
  const motion = options.motion || (previousIndex === nextIndex ? "initial" : nextIndex > previousIndex ? "from-top" : "from-bottom");
  currentProductKey = nextKey;
  renderProductAccordion(currentProductKey, motion);
  if (!options.silent) {
    showToast(item.title);
  }
}

function closeMobilePanel() {
  mobilePanel?.classList.remove("open");
  menuButton?.setAttribute("aria-expanded", "false");
  mobileAccordions.forEach((accordion) => {
    accordion.setAttribute("aria-expanded", "false");
    const submenu = document.getElementById(accordion.getAttribute("aria-controls"));
    submenu?.setAttribute("aria-hidden", "true");
  });
}

function closeDesktopDropdown(item) {
  const focusedElement = document.activeElement;
  if (focusedElement && item.contains(focusedElement)) {
    focusedElement.blur();
  }
}

function closeLanguageMenu({ blur = false } = {}) {
  languageMenu?.classList.remove("open");
  languageToggle?.setAttribute("aria-expanded", "false");

  if (!blur || !languageMenu) return;

  const focusedElement = document.activeElement;
  if (focusedElement && languageMenu.contains(focusedElement)) {
    focusedElement.blur();
  }
}

function getLanguageRouteTarget(code) {
  const hash = window.location.hash || "";
  if (code === "en" && !isEnglishRoute()) {
    return `en.html${hash}`;
  }
  if (code !== "en" && isEnglishRoute()) {
    return `cn.html${hash}`;
  }
  return "";
}

desktopDropdownItems.forEach((item) => {
  item.addEventListener("mouseleave", () => closeDesktopDropdown(item));
});

$$(".desktop-nav a, .mobile-panel a").forEach((link) => {
  link.addEventListener("click", () => {
    closeMobilePanel();
  });
});

const observer = new IntersectionObserver(
  (entries) => {
    const visible = entries
      .filter((entry) => entry.isIntersecting)
      .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];
    if (!visible) return;
    const sectionId = visible.target.id;
    $$(".desktop-nav .nav-trigger").forEach((link) => {
      const targetId = link.dataset.section || link.getAttribute("href")?.replace("#", "");
      link.classList.toggle("active", targetId === sectionId);
    });
    queueRouteHashSync(sectionId);
  },
  { rootMargin: "-35% 0px -50% 0px", threshold: [0.1, 0.35, 0.6] }
);

routeSectionIds.forEach((id) => {
  const section = document.getElementById(id);
  if (section) observer.observe(section);
});

window.addEventListener("hashchange", () => {
  if (performance.now() < routeHashClickRestoreUntil) return;
  restoreRouteHashScroll();
});

document.addEventListener(
  "click",
  (event) => {
    const link = event.target.closest("a[href^='#']");
    const href = link?.getAttribute("href");
    if (href && href.length > 1) {
      routeHashClickRestoreUntil = performance.now() + 1200;
    }
  },
  true
);

