menuButton?.addEventListener("click", () => {
  const isOpen = !mobilePanel.classList.contains("open");
  if (isOpen) {
    mobilePanel.classList.add("open");
    menuButton.setAttribute("aria-expanded", "true");
  } else {
    closeMobilePanel();
  }
});

mobileAccordions.forEach((accordion) => {
  accordion.addEventListener("click", () => {
    const isOpen = accordion.getAttribute("aria-expanded") === "true";
    accordion.setAttribute("aria-expanded", String(!isOpen));
    const submenu = document.getElementById(accordion.getAttribute("aria-controls"));
    submenu?.setAttribute("aria-hidden", String(isOpen));
  });
});

languageToggle?.addEventListener("click", (event) => {
  event.stopPropagation();
  const isOpen = languageMenu.classList.toggle("open");
  languageToggle.setAttribute("aria-expanded", String(isOpen));
  if (!isOpen) {
    languageToggle.blur();
  }
});

languageMenu?.addEventListener("mouseleave", () => {
  closeLanguageMenu({ blur: true });
});

$$("[data-language-option]").forEach((option) => {
  option.addEventListener("click", () => {
    const languageName = option.dataset.languageOption || option.textContent.trim();
    const config = languageOptionConfig[languageName] || languageOptionConfig["简体中文"];
    if (config.url) {
      closeLanguageMenu({ blur: true });
      window.location.href = resolveSiteHref(config.url);
      return;
    }
    const routeTarget = getLanguageRouteTarget(config.code);
    if (routeTarget) {
      closeLanguageMenu({ blur: true });
      window.location.href = routeTarget;
      return;
    }
    applyLanguage(config.code, config.label);
    closeLanguageMenu({ blur: true });
  });
});

document.addEventListener("click", (event) => {
  if (!languageMenu || languageMenu.contains(event.target)) return;
  closeLanguageMenu();
});

$$("[data-news]").forEach((card) => {
  card.addEventListener("click", (event) => {
    if (event.target.closest("[data-news-prev], [data-news-next]")) return;

    const url = card.dataset.newsUrl;
    if (url) window.open(url, "_blank", "noopener");
  });
});

